{
  "type": "AdaptiveCard",
  "$schema": "http://adaptivecards.io/schemas/adaptive-card.json",
  "version": "1.4",
  "body": [
    {
      "type": "Container",
      "style": "emphasis",
      "items": [
        {
          "type": "ColumnSet",
          "columns": [
            {
              "type": "Column",
              "width": "auto",
              "items": [
                {
                  "type": "Image",
                  "url": "https://adaptivecards.io/content/check.png",
                  "size": "small"
                }
              ]
            },
            {
              "type": "Column",
              "width": "stretch",
              "items": [
                {
                  "type": "TextBlock",
                  "text": "✅ Expense Approved & Submitted",
                  "size": "large",
                  "weight": "bolder",
                  "color": "good"
                }
              ]
            }
          ]
        }
      ]
    },
    {
      "type": "Container",
      "spacing": "medium",
      "items": [
        {
          "type": "TextBlock",
          "text": "**Expense Details**",
          "weight": "bolder",
          "size": "medium"
        },
        {
          "type": "FactSet",
          "facts": [
            {
              "title": "Submitter:",
              "value": "Roel Schenk"
            },
            {
              "title": "Expense Type:",
              "value": "Customer Dinner"
            },
            {
              "title": "Amount:",
              "value": "€200"
            },
            {
              "title": "Date:",
              "value": "March 5, 2026"
            },
            {
              "title": "Merchant:",
              "value": "Contoso Restaurant"
            },
            {
              "title": "Attendees:",
              "value": "4 people (Roel, Henry, Dieter - MSFT, John - Contoso)"
            },
            {
              "title": "Per Person Cost:",
              "value": "€50/person"
            },
            {
              "title": "Alcohol:",
              "value": "0% (none)"
            },
            {
              "title": "Approver:",
              "value": "Henry Jammes (M2 Manager)"
            },
            {
              "title": "Report ID:",
              "value": "#8"
            }
          ]
        }
      ]
    },
    {
      "type": "Container",
      "spacing": "medium",
      "style": "accent",
      "items": [
        {
          "type": "TextBlock",
          "text": "**Validation & Reasoning**",
          "weight": "bolder",
          "size": "medium"
        },
        {
          "type": "TextBlock",
          "text": "✅ **Customer Dinner Classification**: Valid - External attendee present (John from Contoso)",
          "wrap": true,
          "spacing": "small"
        },
        {
          "type": "TextBlock",
          "text": "✅ **Per-Person Limit**: €50/person is well below the $100/person policy limit",
          "wrap": true,
          "spacing": "small"
        },
        {
          "type": "TextBlock",
          "text": "✅ **Approver Authority**: €200 (~$220) is within Henry's M2 approval limit ($10,000)",
          "wrap": true,
          "spacing": "small"
        },
        {
          "type": "TextBlock",
          "text": "✅ **Documentation**: Complete - includes business purpose, attendees with affiliations, merchant, and date",
          "wrap": true,
          "spacing": "small"
        },
        {
          "type": "TextBlock",
          "text": "✅ **Alcohol Composition**: No alcohol (0%) - no additional review required",
          "wrap": true,
          "spacing": "small"
        }
      ]
    },
    {
      "type": "Container",
      "spacing": "medium",
      "items": [
        {
          "type": "TextBlock",
          "text": "**Action Taken**",
          "weight": "bolder",
          "size": "medium"
        },
        {
          "type": "TextBlock",
          "text": "✓ Expense report created: 'Customer Dinner - Contoso' (Report ID: 8)\n\n✓ Line item added: €200 for customer dinner with 4 attendees\n\n✓ Submitted to Henry Jammes for approval",
          "wrap": true
        }
      ]
    }
  ]
}
